# City code index: code -> city entry
CITY_INDEX = {cc["code"].upper(): cc for cc in CITY_CODES}

# Reverse index: airport IATA -> city code(s) it belongs to
AIRPORT_CITY_INDEX = {}
for _cc in CITY_CODES:
    for _ap in _cc["airports"] + _cc.get("historical", []):
        AIRPORT_CITY_INDEX.setdefault(_ap.upper(), []).append(_cc["code"])

# ─────────────────────────────────────────────────────────────────────────────
# Indexes
# ─────────────────────────────────────────────────────────────────────────────
IATA_INDEX = {a["iata"].upper(): a for a in AIRPORTS}
ICAO_INDEX = {a["icao"].upper(): a for a in AIRPORTS}

# ─────────────────────────────────────────────────────────────────────────────
# Formatting helpers
# ─────────────────────────────────────────────────────────────────────────────
RESET  = "\033[0m"
BOLD   = "\033[1m"
CYAN   = "\033[36m"
YELLOW = "\033[33m"
GREEN  = "\033[32m"
RED    = "\033[31m"
DIM    = "\033[2m"

def c(color, text):
    return f"{color}{text}{RESET}"

def fmt_airport(a, verbose=False):
    lines = []
    lines.append(c(BOLD + CYAN, f"\n  ✈  {a['name']}"))
    lines.append(f"  {'─' * 52}")
    lines.append(f"  {c(YELLOW, 'IATA:')}  {c(BOLD, a['iata'])}    {c(YELLOW, 'ICAO:')}  {c(BOLD, a['icao'])}")
    lines.append(f"  {c(YELLOW, 'City:')}  {a['city']},  {a['country']}")
    city_codes = AIRPORT_CITY_INDEX.get(a['iata'].upper(), [])
    if city_codes:
        cc_parts = [f"{c(BOLD, cc)}  ({CITY_INDEX[cc]['name']})" for cc in city_codes]
        lines.append(f"  {c(YELLOW, 'Metro code:')}  {',  '.join(cc_parts)}")
    lines.append(f"  {c(YELLOW, 'Timezone:')}  {a['tz']}")
    lines.append(f"  {c(YELLOW, 'Coordinates:')}  {a['lat']:+.4f}°,  {a['lon']:+.4f}°")
    lines.append(f"  {c(YELLOW, 'Elevation:')}  {a['alt']:,} ft  ({int(a['alt'] * 0.3048):,} m)")
    if a.get('wiki'):
        lines.append(f"  {c(YELLOW, 'Wikipedia:')}  {a['wiki']}")
    lines.append("")
    return "\n".join(lines)

def fmt_airport_short(a):
    return (
        f"  {c(BOLD, a['iata'])} / {c(BOLD, a['icao'])}  "
        f"{a['name'][:42]:<42}  "
        f"{a['city']}, {a['country']}"
    )

def fmt_city(cc):
    """Format a city code entry for display."""
    active = cc["airports"]
    hist   = cc.get("historical", [])
    ap_strs = []
    for code in active:
        a = IATA_INDEX.get(code.upper())
        label = a["name"] if a else code
        ap_strs.append(f"    {c(BOLD, code)}  {label}")
    lines = []
    lines.append(c(BOLD + CYAN, f"\n  ✈  {cc['name']}  —  City Code: {c(BOLD, cc['code'])}"))
    lines.append(f"  {'─' * 52}")
    lines.append(f"  {c(YELLOW, 'Country:')}  {cc['country']}")
    lines.append(f"  {c(YELLOW, 'Active airports:')}")
    lines.extend(ap_strs)
    if hist:
        hist_strs = []
        for code in hist:
            a = IATA_INDEX.get(code.upper())
            label = a["name"] if a else code
            hist_strs.append(f"    {c(DIM, code)}  {c(DIM, label)}")
        lines.append(f"  {c(YELLOW, 'Historical airports:')}")
        lines.extend(hist_strs)
    if cc.get("wiki"):
        lines.append(f"  {c(YELLOW, 'Wikipedia:')}  {cc['wiki']}")
    lines.append("")
    return "\n".join(lines)

# ─────────────────────────────────────────────────────────────────────────────
# Lookup logic
# ─────────────────────────────────────────────────────────────────────────────
def lookup(code):
    code = code.strip().upper()
    if code in IATA_INDEX:
        return IATA_INDEX[code], "IATA"
    if code in ICAO_INDEX:
        return ICAO_INDEX[code], "ICAO"
    if code in CITY_INDEX:
        return CITY_INDEX[code], "CITY"
    return None, None

def search(query):
    q = query.lower()
    results = []
    for a in AIRPORTS:
        if (q in a["name"].lower()
                or q in a["city"].lower()
                or q in a["country"].lower()
                or q in a["iata"].lower()
                or q in a["icao"].lower()):
            results.append(a)
    return results

def list_country(country_query):
    q = country_query.lower()
    return [a for a in AIRPORTS if q in a["country"].lower()]

def haversine_km(lat1, lon1, lat2, lon2):
    R = 6371
    dlat = radians(lat2 - lat1)
    dlon = radians(lon2 - lon1)
    a = sin(dlat/2)**2 + cos(radians(lat1)) * cos(radians(lat2)) * sin(dlon/2)**2
    return R * 2 * atan2(sqrt(a), sqrt(1 - a))

def nearest(lat, lon, n=5):
    scored = sorted(AIRPORTS, key=lambda a: haversine_km(lat, lon, a["lat"], a["lon"]))
    return [(a, haversine_km(lat, lon, a["lat"], a["lon"])) for a in scored[:n]]

# ─────────────────────────────────────────────────────────────────────────────
# JSON export
# ─────────────────────────────────────────────────────────────────────────────
def to_dict(a):
    city_codes = AIRPORT_CITY_INDEX.get(a["iata"].upper(), [])
    return {
        "name": a["name"],
        "city": a["city"],
        "country": a["country"],
        "iata": a["iata"],
        "icao": a["icao"],
        "metro_codes": city_codes,
        "latitude": a["lat"],
        "longitude": a["lon"],
        "elevation_ft": a["alt"],
        "timezone": a["tz"],
        "wikipedia": a.get("wiki", ""),
    }

def city_to_dict(cc):
    return {
        "code": cc["code"],
        "name": cc["name"],
        "country": cc["country"],
        "airports": cc["airports"],
        "historical": cc.get("historical", []),
        "wikipedia": cc.get("wiki", ""),
    }

# ─────────────────────────────────────────────────────────────────────────────
# CLI
# ─────────────────────────────────────────────────────────────────────────────
def build_parser():
    p = argparse.ArgumentParser(
        prog="airport_lookup",
        description=(
            "✈  Airport Routing Code Lookup\n"
            "Supports IATA (e.g. LAX) and ICAO (e.g. KLAX) codes.\n"
        ),
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
examples:
  airport_lookup LAX
  airport_lookup KLAX
  airport_lookup LAX JFK NRT
  airport_lookup NYC                  (city/metro code)
  airport_lookup LON TYO              (multiple city codes)
  airport_lookup --search london
  airport_lookup --list-country Japan
  airport_lookup --list-cities
  airport_lookup --nearest 51.5 -0.12
  airport_lookup LAX --json
  airport_lookup --stats
        """,
    )
    p.add_argument(
        "codes",
        nargs="*",
        metavar="CODE",
        help="IATA or ICAO code(s) to look up",
    )
    p.add_argument(
        "--search", "-s",
        metavar="QUERY",
        help="Search airports by name, city, or country",
    )
    p.add_argument(
        "--list-country", "-l",
        metavar="COUNTRY",
        help="List all airports in a given country",
    )
    p.add_argument(
        "--nearest", "-n",
        nargs=2,
        metavar=("LAT", "LON"),
        type=float,
        help="Find the 5 nearest airports to given coordinates",
    )
    p.add_argument(
        "--json", "-j",
        action="store_true",
        help="Output results as JSON",
    )
    p.add_argument(
        "--stats",
        action="store_true",
        help="Show database statistics",
    )
    p.add_argument(
        "--list-cities",
        action="store_true",
        help="List all city/metro codes in the database",
    )
    return p

def main():
    parser = build_parser()
    args = parser.parse_args()

    # ── list-cities ───────────────────────────────────────────────────────────
    if args.list_cities:
        if args.json:
            print(json.dumps([city_to_dict(cc) for cc in CITY_CODES], indent=2))
            return
        print(c(BOLD + CYAN, f"\n  ✈  City / Metro Codes  ({len(CITY_CODES)} entries)"))
        print(f"  {'─' * 70}")
        for cc in sorted(CITY_CODES, key=lambda x: x['name']):
            ap_list = ", ".join(cc["airports"])
            print(f"  {c(BOLD, cc['code'])}  {cc['name']:<22} {cc['country']:<22} → {ap_list}")
        print()
        return

    # ── stats ─────────────────────────────────────────────────────────────────
    if args.stats:
        countries = sorted(set(a["country"] for a in AIRPORTS))
        print(c(BOLD + CYAN, f"\n  ✈  Airport Database Statistics"))
        print(f"  {'─' * 40}")
        print(f"  Total airports : {c(BOLD, str(len(AIRPORTS)))}")
        print(f"  City codes     : {c(BOLD, str(len(CITY_CODES)))}")
        print(f"  Countries      : {c(BOLD, str(len(countries)))}")
        print(f"\n  Countries covered:")
        for co in countries:
            count = sum(1 for a in AIRPORTS if a["country"] == co)
            print(f"    {co:<30} {count} airport{'s' if count > 1 else ''}")
        print()
        return

    # ── nearest ───────────────────────────────────────────────────────────────
    if args.nearest:
        lat, lon = args.nearest
        results = nearest(lat, lon)
        if args.json:
            print(json.dumps([{**to_dict(a), "distance_km": round(d, 1)} for a, d in results], indent=2))
            return
        print(c(BOLD + CYAN, f"\n  ✈  5 Nearest Airports to ({lat:+.4f}, {lon:+.4f})"))
        print(f"  {'─' * 60}")
        for a, dist in results:
            print(f"  {c(BOLD, a['iata'])} / {c(BOLD, a['icao'])}  {c(GREEN, f'{dist:,.0f} km')}  "
                  f"{a['name'][:36]} — {a['city']}, {a['country']}")
        print()
        return

    # ── search ────────────────────────────────────────────────────────────────
    if args.search:
        results = search(args.search)
        if not results:
            print(c(RED, f"\n  No airports found matching '{args.search}'\n"))
            sys.exit(1)
        if args.json:
            print(json.dumps([to_dict(a) for a in results], indent=2))
            return
        print(c(BOLD + CYAN, f"\n  ✈  Search results for '{args.search}'  ({len(results)} found)"))
        print(f"  {'─' * 70}")
        for a in results:
            print(fmt_airport_short(a))
        print()
        return

    # ── list-country ──────────────────────────────────────────────────────────
    if args.list_country:
        results = list_country(args.list_country)
        if not results:
            print(c(RED, f"\n  No airports found for country '{args.list_country}'\n"))
            sys.exit(1)
        if args.json:
            print(json.dumps([to_dict(a) for a in results], indent=2))
            return
        label = results[0]["country"] if results else args.list_country
        print(c(BOLD + CYAN, f"\n  ✈  Airports in {label}  ({len(results)} found)"))
        print(f"  {'─' * 70}")
        for a in results:
            print(fmt_airport_short(a))
        print()
        return

    # ── code lookup ───────────────────────────────────────────────────────────
    if not args.codes:
        parser.print_help()
        return

    found, not_found = [], []
    for code in args.codes:
        a, kind = lookup(code)
        if a:
            found.append((a, kind))
        else:
            not_found.append(code)

    if args.json:
        out = []
        for result, kind in found:
            out.append(city_to_dict(result) if kind == "CITY" else to_dict(result))
        print(json.dumps(out, indent=2))
        if not_found:
            for code in not_found:
                sys.stderr.write(f"Not found: {code}\n")
        return

    for result, kind in found:
        if kind == "CITY":
            print(fmt_city(result))
        else:
            print(fmt_airport(result))

    for code in not_found:
        print(c(RED, f"\n  ✗  '{code}' — code not found in database."))
        # suggest close IATA / ICAO / city matches
        suggestions = [k for k in list(IATA_INDEX) + list(ICAO_INDEX) + list(CITY_INDEX)
                       if k.startswith(code[:2].upper())][:4]
        if suggestions:
            print(c(DIM, f"     Did you mean: {', '.join(suggestions)}?"))
        print()

    if not_found:
        sys.exit(1)


if __name__ == "__main__":
    main()